const var ModwheelDisplay = Content.addPanel("ModwheelDisplay", 38, 60);
Content.setPropertiesFromJSON("ModwheelDisplay", {"width": 50, "height": 180});

const var PitchWheelDisplay = Content.addPanel("PitchWheelDisplay", 110, 60);
Content.setPropertiesFromJSON("PitchWheelDisplay", {"width": 50, "height": 180});

ModwheelDisplay.setPaintRoutine(function(g)
{
    g.fillAll(0xFF222222);
    g.setColour(0xFF666666);
    var h = this.getValue() * this.getHeight();
    g.fillRect([0, this.getHeight() - h, this.getWidth(), h]);
});

PitchWheelDisplay.setPaintRoutine(function(g)
{
    g.fillAll(0xFF222222);
    g.setColour(0xFF666666);
    var h = 0.5 - this.getValue();
    var offset = Math.min(1.0 - this.getValue(), 0.5) * this.getHeight();
    g.fillRect([0, offset, this.getWidth(), Math.abs(h) * this.getHeight()]);
});

const var Panel1 = Content.getComponent("Panel1");
var yOffset = 0;
const var names = ["Name1", "Name2", "Name3", "Name4"];

Panel1.setPaintRoutine(function(g)
{
    g.setColour(Colours.lightgrey);
    g.drawRoundedRectangle([0, 0, this.getWidth(), this.getHeight()], 6.0, 2.0);
    g.setFont("Arial", 14.0);
    for (n = 0; n < names.length; n++)
        g.drawAlignedText(names[n], [0, (this.getHeight() / names.length * n) + yOffset, this.getWidth(), 20], "centred");
});

const var textTimer = Engine.createTimerObject();
textTimer.setTimerCallback(function()
{
    yOffset -= 1;
    Panel1.repaint();
});
textTimer.startTimer(100);
